.darma-loader-darma-custom-001 {
  width: 40px;
  aspect-ratio: 1;
  background: linear-gradient(var(--loader-color, #00AAFF) 0 0), linear-gradient(var(--loader-secondary-color, #FF00AA) 0 0), var(--loader-color, #00AAFF);
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-001-l1 1.5s infinite;
}
@keyframes darma-loader-darma-custom-001-l1 {
  0% { background-size: 100% 0, 0 100%; }
  30%, 50% { background-size: 100% 0, 100% 100%; }
  80%, 100% { background-size: 100% 100%, 100% 100%; }
}

